use soroban_sdk::{contract, contractimpl, Address, Env, Symbol, Bytes, symbol_short};

#[contractimpl]
impl EventContract {
    pub fn transfer(env: Env, from: Address, to: Address, amount: i128) {
        // Excessive topic count (5)
        env.events().publish((symbol_short!("transfer"), from.clone(), to.clone(), amount, amount), ());

        // Large payload type in topics
        env.events().publish((symbol_short!("log"), Bytes::from_slice(&env, &[1, 2, 3])), ());

        // Safe: 2 plain topics
        env.events().publish((symbol_short!("ok"), from), ());
    }
}
